  ('abondance', 'Ton cœur connaît sa mesure, il sait ce qui est juste.', 'Your heart knows its measure, it knows what is right.', 'purama', 1),
  ('abondance', 'L''abondance est d''abord un état intérieur.', 'Abundance is first an inner state.', 'purama', 1),
  ('abondance', 'Tu peux faire confiance au flux des saisons.', 'You can trust the flow of seasons.', 'purama', 1),
  ('abondance', 'Il y a une place pour tes rêves, même les plus fous.', 'There is a place for your dreams, even the wildest.', 'purama', 1),
  ('abondance', 'Les opportunités se présentent quand tu es disponible.', 'Opportunities appear when you are available.', 'purama', 1),
  ('abondance', 'Tu peux laisser les autres t''aider. C''est une abondance partagée.', 'You can let others help you. It is a shared abundance.', 'purama', 1),
  ('abondance', 'Tu n''as rien à prouver pour avoir droit à la joie.', 'You have nothing to prove to deserve joy.', 'purama', 1),
