  ('protection', 'Tu peux placer un bouclier de lumière autour de toi.', 'You can place a shield of light around you.', 'purama', 1),
  ('protection', 'Tu es intouchable dans ton essence profonde.', 'You are untouchable in your deep essence.', 'purama', 1),
  ('protection', 'Rien ne peut atteindre la flamme au centre de toi.', 'Nothing can reach the flame at your center.', 'purama', 1),
  ('protection', 'Tu peux te tenir à distance de ce qui te fait du mal.', 'You can keep distance from what harms you.', 'purama', 1),
  ('protection', 'Ton non est une bénédiction pour toi.', 'Your no is a blessing for you.', 'purama', 1),
  ('protection', 'Tu peux partir, quitter, t''éloigner, si nécessaire.', 'You can leave, quit, distance yourself, if necessary.', 'purama', 1),
  ('protection', 'Tu n''es pas obligé·e de rester où tu te sens mal.', 'You are not obliged to stay where you feel bad.', 'purama', 1),
  ('protection', 'Ton instinct de protection est juste et sain.', 'Your protective instinct is right and healthy.', 'purama', 1),
  ('protection', 'Tu peux te fier à ce qui te fait serrer le ventre.', 'You can trust what makes your gut tighten.', 'purama', 1),
  ('protection', 'Ton corps est une antenne, écoute-la.', 'Your body is an antenna, listen to it.', 'purama', 1),
  ('protection', 'Tu peux quitter une pièce, un lien, un lieu.', 'You can leave a room, a bond, a place.', 'purama', 1),
  ('protection', 'Tu es fort·e de ton ancrage, pas de ta dureté.', 'You are strong from your rootedness, not your hardness.', 'purama', 1),
  ('protection', 'Tes alliés invisibles comptent plus que tu ne crois.', 'Your invisible allies count more than you believe.', 'purama', 1),
  ('protection', 'Tu es relié·e à quelque chose de plus grand que toi.', 'You are connected to something greater than yourself.', 'purama', 1),
  ('protection', 'L''univers a un œil bienveillant sur toi.', 'The universe has a kind eye on you.', 'purama', 1),
  ('protection', 'Tu peux faire confiance à la vie qui t''entoure.', 'You can trust the life around you.', 'purama', 1),
  ('protection', 'Ta lumière intérieure éloigne l''ombre par sa seule présence.', 'Your inner light keeps shadow away by its mere presence.', 'purama', 1),
  ('protection', 'Tu peux respirer, tu es en sécurité, en ce moment.', 'You can breathe, you are safe, right now.', 'purama', 1),
  ('protection', 'Tes mains sur ton cœur créent un espace protégé.', 'Your hands on your heart create a protected space.', 'purama', 1),
  ('protection', 'Tu peux visualiser une bulle dorée autour de toi.', 'You can visualize a golden bubble around you.', 'purama', 1),
  ('protection', 'Cette bulle laisse passer l''amour, pas l''agression.', 'This bubble lets love through, not aggression.', 'purama', 1),
  ('protection', 'Tu as le droit de te protéger, sans te justifier.', 'You have the right to protect yourself, without justifying.', 'purama', 1),
  ('protection', 'Ton intimité est un trésor, tu es la gardienne de ses clés.', 'Your intimacy is a treasure, you guard its keys.', 'purama', 1),
  ('protection', 'Tu peux reprendre ton énergie, là où tu l''as laissée.', 'You can reclaim your energy, where you left it.', 'purama', 1),
  ('protection', 'Tes pensées sont à toi, tu peux les trier.', 'Your thoughts are yours, you can sort them.', 'purama', 1),
  ('protection', 'Tu peux rendre aux autres ce qui est à eux.', 'You can return to others what is theirs.', 'purama', 1),
  ('protection', 'Ton champ se purifie quand tu respires profondément.', 'Your field purifies when you breathe deeply.', 'purama', 1),
  ('protection', 'L''eau, la nature, le silence te lavent.', 'Water, nature, silence cleanse you.', 'purama', 1),
  ('protection', 'Tu peux te laver des énergies lourdes, par ton souffle.', 'You can cleanse yourself of heavy energies, through your breath.', 'purama', 1),
  ('protection', 'Tu peux choisir ta compagnie, sans être seul·e.', 'You can choose your company, without being alone.', 'purama', 1),
  ('protection', 'Tes soutiens sont plus nombreux que tu ne le vois.', 'Your supports are more numerous than you see.', 'purama', 1),
  ('protection', 'Tu peux appeler à l''aide, même intérieurement.', 'You can call for help, even inwardly.', 'purama', 1),
  ('protection', 'Ton cri silencieux est entendu.', 'Your silent cry is heard.', 'purama', 1),
  ('protection', 'Tu peux compter sur des forces discrètes qui t''aiment.', 'You can count on quiet forces that love you.', 'purama', 1),
  ('protection', 'Tu es protégé·e, même quand tu ne le sens pas.', 'You are protected, even when you don''t feel it.', 'purama', 1),
  ('protection', 'Ton ange intérieur veille en permanence.', 'Your inner angel watches permanently.', 'purama', 1),
  ('protection', 'Tu peux t''entourer de pensées propres et belles.', 'You can surround yourself with clean, beautiful thoughts.', 'purama', 1),
  ('protection', 'Ton intuition fort te dit quand t''éloigner.', 'Your strong intuition tells you when to step away.', 'purama', 1),
  ('protection', 'Tu peux faire le tri dans tes liens.', 'You can sort your connections.', 'purama', 1),
  ('protection', 'Tu n''as pas à subir ce qui te rétrécit.', 'You don''t have to endure what shrinks you.', 'purama', 1),
  ('protection', 'Ta vérité te protège plus que tes mensonges.', 'Your truth protects you more than your lies.', 'purama', 1),
  ('protection', 'Tu peux être doux·ce et protégé·e à la fois.', 'You can be gentle and protected at the same time.', 'purama', 1),
  ('protection', 'La douceur n''est pas la faiblesse.', 'Softness is not weakness.', 'purama', 1),
  ('protection', 'Tu peux porter une armure légère, faite de ton centre.', 'You can wear a light armor, made of your center.', 'purama', 1),
  ('protection', 'Ton centre est inviolable, toujours intact.', 'Your center is inviolable, always intact.', 'purama', 1),
  ('protection', 'Tu peux te centrer en posant la main sur le ventre.', 'You can center yourself by placing a hand on your belly.', 'purama', 1),
  ('protection', 'Ton souffle devient un bouclier souple.', 'Your breath becomes a supple shield.', 'purama', 1),
  ('protection', 'Tu peux habiter ton corps pleinement, personne ne t''en chasse.', 'You can fully inhabit your body, no one chases you out.', 'purama', 1),
  ('protection', 'Tu es chez toi, dans ton corps, dans ta vie.', 'You are home, in your body, in your life.', 'purama', 1),
  ('protection', 'Tu peux renforcer ton ancrage, à tout moment.', 'You can strengthen your rootedness, at any moment.', 'purama', 1),
  ('protection', 'Tes pieds sont des racines vivantes.', 'Your feet are living roots.', 'purama', 1),
  ('protection', 'La terre te porte, elle a toujours porté.', 'The earth carries you, it has always carried.', 'purama', 1),
  ('protection', 'Tu peux faire corps avec ce qui te protège.', 'You can be one with what protects you.', 'purama', 1),
  ('protection', 'Ton intention de paix est un bouclier naturel.', 'Your intention of peace is a natural shield.', 'purama', 1),
  ('protection', 'Tu peux dessiner mentalement un cercle autour de toi.', 'You can mentally draw a circle around you.', 'purama', 1),
  ('protection', 'Ce cercle ne laisse passer que ce qui t''aime.', 'This circle only lets through what loves you.', 'purama', 1),
  ('protection', 'Tu peux bénir ce que tu quittes.', 'You can bless what you leave.', 'purama', 1),
  ('protection', 'Ta bénédiction te libère aussi.', 'Your blessing frees you too.', 'purama', 1),
  ('protection', 'Tu peux relâcher les liens toxiques, avec amour.', 'You can release toxic ties, with love.', 'purama', 1),
  ('protection', 'Tu peux couper symboliquement un cordon qui te pèse.', 'You can symbolically cut a cord that weighs on you.', 'purama', 1),
  ('protection', 'Tes émotions te protègent, elles ne te trahissent pas.', 'Your emotions protect you, they don''t betray you.', 'purama', 1),
  ('protection', 'Ton intuition te tient à l''écart du danger inutile.', 'Your intuition keeps you away from unnecessary danger.', 'purama', 1),
  ('protection', 'Tu peux avoir peur, et agir quand même, protégé·e.', 'You can be afraid, and act anyway, protected.', 'purama', 1),
  ('protection', 'Le courage se nourrit de la certitude d''être soutenu·e.', 'Courage feeds on the certainty of being supported.', 'purama', 1),
  ('protection', 'Tu n''es pas seul·e dans cette vie.', 'You are not alone in this life.', 'purama', 1),
  ('protection', 'Des yeux bienveillants te suivent depuis longtemps.', 'Kind eyes have been following you for a long time.', 'purama', 1),
  ('protection', 'Tu peux te rappeler que tu es aimé·e, toujours.', 'You can remember you are loved, always.', 'purama', 1),
  ('protection', 'Ton cœur est tenu, même quand il vacille.', 'Your heart is held, even when it wavers.', 'purama', 1),
  ('protection', 'Tu peux confier ta peur à quelque chose de plus grand.', 'You can entrust your fear to something greater.', 'purama', 1),
  ('protection', 'Tu es précieux·se, digne de protection et de soin.', 'You are precious, worthy of protection and care.', 'purama', 1),

