  ('paix', 'La paix n''est pas loin, elle est sous ton souffle.', 'Peace is not far, it is beneath your breath.', 'purama', 1),
  ('paix', 'Tu peux t''asseoir, et laisser le silence faire son travail.', 'You can sit, and let silence do its work.', 'purama', 1),
  ('paix', 'Ton calme profond n''a jamais vraiment disparu.', 'Your deep calm has never really disappeared.', 'purama', 1),
  ('paix', 'Tu peux revenir au présent, c''est le seul lieu réel.', 'You can return to the present, it is the only real place.', 'purama', 1),
  ('paix', 'Tes pensées passent, tu restes.', 'Your thoughts pass, you remain.', 'purama', 1),
  ('paix', 'Tu peux observer sans juger, c''est déjà la paix.', 'You can observe without judging, that is already peace.', 'purama', 1),
  ('paix', 'Le silence intérieur est ton allié fidèle.', 'Inner silence is your faithful ally.', 'purama', 1),
  ('paix', 'Tu peux ralentir, la vie ralentit avec toi.', 'You can slow down, life slows with you.', 'purama', 1),
  ('paix', 'Ici, maintenant, tout est là, tout est bien.', 'Here, now, everything is here, everything is well.', 'purama', 1),
  ('paix', 'Tu peux respirer lentement, et tout devient plus simple.', 'You can breathe slowly, and everything becomes simpler.', 'purama', 1),
  ('paix', 'La paix n''est pas l''absence de bruit, c''est ta présence au son.', 'Peace is not the absence of noise, it is your presence to sound.', 'purama', 1),
  ('paix', 'Tu peux te poser, même une minute, et sentir.', 'You can pause, even a minute, and feel.', 'purama', 1),
  ('paix', 'Ton cœur cherche la paix, et il sait où elle est.', 'Your heart seeks peace, and it knows where it is.', 'purama', 1),
  ('paix', 'Tu peux relâcher le besoin que tout soit parfait.', 'You can release the need for everything to be perfect.', 'purama', 1),
  ('paix', 'La paix vient quand tu cesses de lutter avec l''instant.', 'Peace comes when you stop fighting with the moment.', 'purama', 1),
  ('paix', 'Tu peux accepter ce qui est, sans t''y résigner.', 'You can accept what is, without resigning yourself.', 'purama', 1),
  ('paix', 'Ton souffle est la porte la plus simple vers le calme.', 'Your breath is the simplest door to calm.', 'purama', 1),
  ('paix', 'Tu peux t''arrêter, trois respirations suffisent.', 'You can stop, three breaths are enough.', 'purama', 1),
  ('paix', 'La nature en toi est paisible, profondément.', 'Your nature within is peaceful, deeply.', 'purama', 1),
  ('paix', 'Tu es plus vaste que tes agitations.', 'You are vaster than your agitations.', 'purama', 1),
  ('paix', 'Tu peux observer le tourbillon sans y entrer.', 'You can observe the whirlwind without entering it.', 'purama', 1),
  ('paix', 'Ton centre est toujours calme, même quand la surface s''agite.', 'Your center is always calm, even when the surface stirs.', 'purama', 1),
  ('paix', 'Tu peux plonger sous les vagues de ton mental.', 'You can dive beneath the waves of your mind.', 'purama', 1),
  ('paix', 'Au fond, il y a toi, tranquille.', 'At the bottom, there is you, tranquil.', 'purama', 1),
  ('paix', 'Tu peux lâcher ce qui tire en toi.', 'You can release what pulls within you.', 'purama', 1),
  ('paix', 'Ta paix est une retrouvaille, pas une conquête.', 'Your peace is a reunion, not a conquest.', 'purama', 1),
  ('paix', 'Tu peux goûter le silence entre deux pensées.', 'You can taste the silence between two thoughts.', 'purama', 1),
  ('paix', 'L''espace entre tes pensées est ta vraie demeure.', 'The space between your thoughts is your true home.', 'purama', 1),
  ('paix', 'Tu peux arrêter de courir, rien ne s''échappe.', 'You can stop running, nothing escapes.', 'purama', 1),
  ('paix', 'Tu n''as rien à rattraper, tu es déjà là.', 'You have nothing to catch up with, you are already here.', 'purama', 1),
  ('paix', 'Ta respiration est un pont vers la paix.', 'Your breath is a bridge to peace.', 'purama', 1),
  ('paix', 'Tu peux écouter le silence, il a beaucoup à dire.', 'You can listen to silence, it has much to say.', 'purama', 1),
  ('paix', 'La vraie paix n''exclut rien, elle accueille tout.', 'True peace excludes nothing, it welcomes everything.', 'purama', 1),
  ('paix', 'Tu peux être en paix avec ce qui te dérange.', 'You can be at peace with what disturbs you.', 'purama', 1),
  ('paix', 'La paix commence par un oui silencieux à ce qui est.', 'Peace begins with a silent yes to what is.', 'purama', 1),
  ('paix', 'Tu peux poser ton attention sur ce qui va bien.', 'You can place your attention on what is going well.', 'purama', 1),
  ('paix', 'Chaque inspir te ramène à toi.', 'Each inhale brings you back to yourself.', 'purama', 1),
  ('paix', 'Chaque expir laisse partir ce qui n''a plus besoin d''être tenu.', 'Each exhale lets go of what no longer needs to be held.', 'purama', 1),
  ('paix', 'Tu peux te rappeler que tu respires, et tout change.', 'You can remember that you breathe, and everything changes.', 'purama', 1),
  ('paix', 'La paix n''est pas un état à atteindre, c''est un retour.', 'Peace is not a state to reach, it is a return.', 'purama', 1),
  ('paix', 'Tu peux arrêter de te faire la guerre.', 'You can stop making war with yourself.', 'purama', 1),
  ('paix', 'La tendresse envers toi ouvre la paix.', 'Tenderness toward yourself opens peace.', 'purama', 1),
  ('paix', 'Tu peux cesser d''argumenter avec la réalité.', 'You can stop arguing with reality.', 'purama', 1),
  ('paix', 'La résistance crée la souffrance, le oui libère.', 'Resistance creates suffering, yes liberates.', 'purama', 1),
  ('paix', 'Tu peux dire oui, juste pour voir.', 'You can say yes, just to see.', 'purama', 1),
  ('paix', 'La paix aime les esprits ouverts et les cœurs doux.', 'Peace loves open minds and soft hearts.', 'purama', 1),
  ('paix', 'Tu peux déposer tes armes intérieures.', 'You can lay down your inner weapons.', 'purama', 1),
  ('paix', 'Tu n''as personne à combattre en toi.', 'You have no one to fight within you.', 'purama', 1),
  ('paix', 'Ton esprit peut s''apaiser comme un lac au crépuscule.', 'Your mind can calm like a lake at dusk.', 'purama', 1),
  ('paix', 'Tu peux trouver la paix dans un geste simple.', 'You can find peace in a simple gesture.', 'purama', 1),
  ('paix', 'Boire un verre d''eau, lentement, c''est déjà une méditation.', 'Drinking a glass of water, slowly, is already a meditation.', 'purama', 1),
  ('paix', 'Tu peux faire une chose à la fois, pleinement.', 'You can do one thing at a time, fully.', 'purama', 1),
  ('paix', 'La paix se trouve dans l''attention au présent.', 'Peace is found in attention to the present.', 'purama', 1),
  ('paix', 'Tu peux ralentir ta marche, ton pas devient prière.', 'You can slow your walk, your step becomes prayer.', 'purama', 1),
  ('paix', 'Ton corps, quand il ralentit, guide ton esprit.', 'Your body, when it slows, guides your mind.', 'purama', 1),
  ('paix', 'Tu peux choisir la paix, à chaque carrefour.', 'You can choose peace, at every crossroads.', 'purama', 1),
  ('paix', 'La paix n''est pas ennuyeuse, elle est vibrante.', 'Peace is not boring, it is vibrant.', 'purama', 1),
  ('paix', 'Tu peux accueillir la joie dans la paix.', 'You can welcome joy within peace.', 'purama', 1),
  ('paix', 'La paix intérieure devient paix autour de toi.', 'Inner peace becomes peace around you.', 'purama', 1),
  ('paix', 'Tu contribues à la paix du monde quand tu es en paix.', 'You contribute to world peace when you are at peace.', 'purama', 1),
  ('paix', 'Tu peux être un pôle de calme dans ta famille.', 'You can be a pole of calm in your family.', 'purama', 1),
  ('paix', 'Ta respiration tranquille apaise autour de toi.', 'Your quiet breath calms those around you.', 'purama', 1),
  ('paix', 'Tu peux revenir au souffle, chaque fois que tu t''égares.', 'You can return to the breath, each time you wander.', 'purama', 1),
  ('paix', 'La vie te parle à travers le silence.', 'Life speaks to you through silence.', 'purama', 1),
  ('paix', 'Tu peux l''écouter, elle a des choses tendres à te dire.', 'You can listen, it has tender things to tell you.', 'purama', 1),
  ('paix', 'Tes nuits calmes préparent tes journées claires.', 'Your calm nights prepare your clear days.', 'purama', 1),
  ('paix', 'La paix, c''est aussi faire moins, mieux.', 'Peace is also doing less, better.', 'purama', 1),
  ('paix', 'Tu peux lâcher les choses qui ne comptent plus.', 'You can let go of things that no longer matter.', 'purama', 1),
  ('paix', 'Ta liste de priorités peut rétrécir.', 'Your list of priorities can shrink.', 'purama', 1),
  ('paix', 'Tu peux dire non à ce qui t''agite inutilement.', 'You can say no to what stirs you up unnecessarily.', 'purama', 1),
  ('paix', 'La paix grandit dans les espaces que tu crées.', 'Peace grows in the spaces you create.', 'purama', 1),
  ('paix', 'Tu peux créer de l''espace autour de toi, dedans aussi.', 'You can create space around you, inside too.', 'purama', 1),
  ('paix', 'L''inactivité choisie est un trésor.', 'Chosen inactivity is a treasure.', 'purama', 1),
  ('paix', 'Tu peux ne rien faire, avec grâce.', 'You can do nothing, with grace.', 'purama', 1),
  ('paix', 'La paix intérieure est un acte de résistance.', 'Inner peace is an act of resistance.', 'purama', 1),
  ('paix', 'Tu peux cultiver ta paix, comme un jardin précieux.', 'You can cultivate your peace, like a precious garden.', 'purama', 1),
  ('paix', 'Les mauvaises herbes du mental, tu peux les arracher.', 'The weeds of the mind, you can pull them.', 'purama', 1),
  ('paix', 'Tu peux choisir les pensées que tu arroses.', 'You can choose the thoughts you water.', 'purama', 1),
  ('paix', 'Ta paix n''attend pas que tout soit résolu.', 'Your peace doesn''t wait for everything to be resolved.', 'purama', 1),
  ('paix', 'Tu peux être en paix avec l''incomplétude.', 'You can be at peace with incompleteness.', 'purama', 1),
  ('paix', 'La vie est un processus, pas un résultat.', 'Life is a process, not a result.', 'purama', 1),
  ('paix', 'Tu peux savourer le chemin, pas seulement l''arrivée.', 'You can savor the path, not just the arrival.', 'purama', 1),
  ('paix', 'Ta paix est contagieuse, sans que tu le saches.', 'Your peace is contagious, without you knowing.', 'purama', 1),
  ('paix', 'Tu peux être une oasis, pour toi d''abord.', 'You can be an oasis, for yourself first.', 'purama', 1),
  ('paix', 'Ton silence est éloquent, n''aie pas peur de lui.', 'Your silence is eloquent, don''t be afraid of it.', 'purama', 1),
  ('paix', 'Tu peux te taire et écouter ce que le corps dit.', 'You can be silent and listen to what the body says.', 'purama', 1),
  ('paix', 'Ton corps est un maître de paix, si tu l''écoutes.', 'Your body is a master of peace, if you listen.', 'purama', 1),
  ('paix', 'Tu peux marcher sans but, juste pour sentir.', 'You can walk aimlessly, just to feel.', 'purama', 1),
  ('paix', 'La paix se ressent dans les orteils aussi.', 'Peace is felt in the toes too.', 'purama', 1),
  ('paix', 'Tu peux sentir chaque partie de ton corps, une par une.', 'You can feel each part of your body, one by one.', 'purama', 1),
  ('paix', 'Ce balayage intérieur installe la paix.', 'This inner scan installs peace.', 'purama', 1),
  ('paix', 'Tu peux t''offrir cinq minutes de silence, maintenant.', 'You can offer yourself five minutes of silence, now.', 'purama', 1),
  ('paix', 'Le silence est la plus belle des musiques.', 'Silence is the most beautiful music.', 'purama', 1),
  ('paix', 'Tu peux entendre ton cœur, quand le bruit se tait.', 'You can hear your heart, when noise quiets.', 'purama', 1),
  ('paix', 'Ton cœur bat la mesure d''une chanson très ancienne.', 'Your heart beats the rhythm of a very ancient song.', 'purama', 1),
  ('paix', 'Tu peux t''accorder à cette mesure, c''est ta paix.', 'You can attune to that rhythm, it is your peace.', 'purama', 1),
  ('paix', 'La paix règne en toi, sous les couches d''agitation.', 'Peace reigns within you, beneath layers of agitation.', 'purama', 1),
  ('paix', 'Tu peux toujours y revenir, elle ne t''a jamais quitté·e.', 'You can always return to it, it has never left you.', 'purama', 1),
